/* ── Three-dots row menu button ──
   Faintly visible by default so touch devices (which have no :hover state)
   can still perceive and tap the trigger — WCAG 2.5.1 / 2.5.8. Fully revealed
   on row hover, keyboard focus (:focus-within on the row covers focus moving
   through the row; :focus-visible on the button itself), or when its popup is
   open. Uses the same muted-foreground / brighten-on-hover pattern as the
   dialog close button. */
.row-menu-btn {
  background: none;
  border: none;
  color: #9a9a9a;
  cursor: pointer;
  padding: 6px 8px;
  min-width: 24px;
  min-height: 24px;
  font-size: 16px;
  line-height: 1;
  border-radius: 4px;
  opacity: 0.35;
  pointer-events: none;
}
.browse-table tbody tr:hover .row-menu-btn,
.browse-table tbody tr:focus-within .row-menu-btn,
.row-menu-btn:focus-visible,
.row-menu-btn[aria-expanded='true'] {
